/// <summary>
/// Source-of-truth helper for the user-level Visual Relay dotenv file at
/// <c>$XDG_CONFIG_HOME/visual-relay/.env</c> (falling back to
/// <c>$HOME/.config/visual-relay/.env</c>).
///
/// Resolution precedence: <b>process env &gt; user-level .env</b>.
///
/// Environment accessor seam: every env-dependent method accepts an optional
/// <see cref="IEnvironmentAccessor"/> parameter. When null (default), the real
/// process environment is used. Tests inject a <c>DictionaryEnvironmentAccessor</c>
/// by passing it directly — no process-global static.
/// </summary>
public static class KeyEnvFile
{
    private const string DirName = "visual-relay";
    private const string FileName = ".env";

    // ── Environment accessor seam (testability) ──────────────────────────

    /// <summary>
    /// Reads an environment variable through <paramref name="accessor"/> when
    /// non-null, falling back to the real process environment. The fallback is
    /// by design: callers (e.g. the settings panel) inject an accessor that
    /// overrides only specific keys and expect the rest to resolve against the
    /// real environment.
    /// </summary>
    public static string? GetEnv(string name, IEnvironmentAccessor? accessor = null) =>
        accessor?.GetEnvironmentVariable(name)
        ?? Environment.GetEnvironmentVariable(name);

    // ── Path resolution ──────────────────────────────────────────────────

    /// <summary>
    /// Public accessor for the user-level dotenv path, resolved against the real
    /// process environment. The backend lifecycle reads this to source provider
    /// keys at proxy start (the user-level tier of the precedence chain).
    /// </summary>
    public static string ResolvePathForCurrentUser() => ResolvePathForCurrentUser(null);

    /// <summary>
    /// Public accessor for the user-level dotenv path, reading
    /// <c>XDG_CONFIG_HOME</c> and <c>HOME</c> through <paramref name="accessor"/>
    /// (or the real process environment when null). Threads the same env seam as
    /// the other settings/keys methods so callers stay consistent and testable.
    /// </summary>
    public static string ResolvePathForCurrentUser(IEnvironmentAccessor? accessor) =>
        ResolvePath(accessor);

    /// <summary>
    /// Public accessor for <see cref="GetUnsetKeys(string, IEnvironmentAccessor?)"/>:
    /// keys/values from <paramref name="filePath"/> not already set in the process
    /// environment. The backend lifecycle uses this to layer provider keys onto a
    /// spawned proxy with process-env-wins precedence.
    /// </summary>
    public static Dictionary<string, string> GetUnsetKeysPublic(string filePath) =>
        GetUnsetKeys(filePath);

    /// <summary>
    /// Returns the user-level dotenv path, reading <c>XDG_CONFIG_HOME</c> and
    /// <c>HOME</c> from <paramref name="accessor"/> (or the real process env).
    /// </summary>
    private static string ResolvePath(IEnvironmentAccessor? accessor = null) =>
        ResolvePath(GetEnv("XDG_CONFIG_HOME", accessor), GetEnv("HOME", accessor));

