internal sealed class DictionaryEnvironmentAccessor : IEnvironmentAccessor
{
    private readonly System.Collections.Concurrent.ConcurrentDictionary<string, string?> _vars = new();

    public string? this[string name]
    {
        get => _vars.GetValueOrDefault(name);
        set { if (value is null) _vars.TryRemove(name, out _); else _vars[name] = value; }
    }

    public string? GetEnvironmentVariable(string name) => this[name];
}

/// <summary>
/// Creates a <see cref="DictionaryEnvironmentAccessor"/> pre-seeded with
/// <c>HOME</c> pointing at a unique throwaway directory under
/// <c>Path.GetTempPath()</c>. Every test that needs "an environment that
/// resolves to a throwaway config dir" uses this instead of
/// <c>new DictionaryEnvironmentAccessor()</c>, so no config write ever
/// lands in the developer's real <c>~/.config</c>.
/// </summary>
internal static class IsolatedAccessor
{
    internal static DictionaryEnvironmentAccessor Create()
    {
        var home = Path.Combine(Path.GetTempPath(), "visual-relay-isolated", Guid.NewGuid().ToString("N"));
        Directory.CreateDirectory(home);
        return new DictionaryEnvironmentAccessor { ["HOME"] = home };
    }
}

