    private static int FindLineNumber(string content, string pattern)
    {
        var idx = content.IndexOf(pattern, StringComparison.Ordinal);
        if (idx < 0) return 0;
        // Count newlines up to the match position (1-based line number).
        var line = 1;
        for (int i = 0; i < idx; i++)
            if (content[i] == '\n')
                line++;
        return line;
    }

    /// <summary>
    /// Regression guard: the config seam must reach the process environment only
    /// through an injected <see cref="IEnvironmentAccessor"/>. The sole concrete
    /// real-env implementation is <see cref="ProcessEnvironmentAccessor"/>, so any
    /// other direct <c>Environment.GetEnvironmentVariable</c> /
    /// <c>Environment.GetEnvironmentVariables</c> call inside
    /// <c>src/VisualRelay.Core/Configuration/</c> is a silent-fallback regression.
    /// <c>XdgConfig</c>'s Windows <c>Environment.GetFolderPath(ApplicationData)</c>
    /// call is a different API and is intentionally allowed.
    /// </summary>
    [Fact]
    public void ConfigurationDirectory_UsesAccessorSeam_NoDirectRealEnvFallback()
    {
        var configDir = Path.Combine(RepoSetup.Root, "src", "VisualRelay.Core", "Configuration");
        if (!Directory.Exists(configDir))
        {
            // The directory might not exist in unusual layouts — skip gracefully.
            return;
        }

        var allowedFile = "ProcessEnvironmentAccessor.cs";
        var violations = new List<string>();

        foreach (var file in Directory.EnumerateFiles(configDir, "*.cs", SearchOption.AllDirectories))
        {
            var fileName = Path.GetFileName(file);
            if (string.Equals(fileName, allowedFile, StringComparison.OrdinalIgnoreCase))
                continue;

            var content = File.ReadAllText(file);
            if (content.Contains("Environment.GetEnvironmentVariable", StringComparison.Ordinal)
                || content.Contains("Environment.GetEnvironmentVariables", StringComparison.Ordinal))
            {
                var relative = Path.GetRelativePath(RepoSetup.Root, file);
                violations.Add(
                    $"{relative}: calls Environment.GetEnvironmentVariable(s) directly " +
                    "— the config seam must reach the process environment only through " +
                    "an injected IEnvironmentAccessor. The sole concrete real-env " +
                    "implementation is ProcessEnvironmentAccessor.cs.");
            }
        }

        Assert.True(violations.Count == 0,
            "Configuration directory contains direct real-env calls outside " +
            "ProcessEnvironmentAccessor.cs:\n" +
            string.Join("\n", violations) +
            "\n\nThese calls are a silent-fallback regression — they bypass the " +
            "IEnvironmentAccessor seam and read/write the real process environment " +
            "even when a test provides an isolated accessor. Remove the direct " +
            "Environment.GetEnvironmentVariable(s) call and use the injected accessor.");
    }
}

